const css = `
@import url('https://fonts.googleapis.com/css2?family=Sora:wght@400;500;600;700;800&family=Outfit:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500;700&display=swap');
* { box-sizing: border-box; }
body { margin: 0; background: #05060f; }
::-webkit-scrollbar { height: 9px; width: 9px; }
::-webkit-scrollbar-thumb { background: rgba(120,150,255,.4); border-radius: 100px; }
::-webkit-scrollbar-track { background: transparent; }
@keyframes spin { to { transform: rotate(360deg); } }
@keyframes pulse { 0%,100% { opacity:1; } 50% { opacity:.4; } }
@keyframes fadeUp { from { opacity:0; transform: translateY(22px); } to { opacity:1; transform: translateY(0); } }
@keyframes shimmer { 0% { transform: translateX(-120%) skewX(-20deg); } 100% { transform: translateX(220%) skewX(-20deg); } }
@keyframes floaty { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-10px); } }
.fadeup { animation: fadeUp .6s ease both; }
.shine { display: none; }
button { transition: .2s; }
button:hover { filter: brightness(1.12); }
.hoverlift:hover { transform: translateY(-4px); box-shadow: 0 16px 40px rgba(59,130,246,.25) !important; }
.navlink:hover { color: #fff !important; }
.qaitem:hover { border-color: rgba(120,150,255,.5) !important; background: rgba(120,150,255,.1) !important; }
.techbadge:hover { transform: translateY(-5px) scale(1.06); }
input:focus { border-color: rgba(120,150,255,.65) !important; }
@media (max-width: 1080px) {
  [data-herotop] { grid-template-columns: 1fr !important; }
  [data-twocol] { grid-template-columns: 1fr !important; }
  [data-pugrid] { grid-template-columns: 1fr 1fr !important; }
  [data-globe] { display:none !important; }
}
@media (max-width: 860px) {
  .navlinks { display: none !important; }
  .menubtn { display: block !important; }
  [data-heromain] { grid-template-columns: 1fr !important; justify-items: center; text-align: center; }
  [data-herotext] { text-align: center; }
  [data-heroname] { white-space: normal !important; }
  [data-quotebox] { margin-left:auto; margin-right:auto; }
  [data-herobtns] { justify-content: center; }
  [data-dashgrid] { grid-template-columns: 1fr 1fr !important; }
  [data-qagrid] { grid-template-columns: 1fr !important; }
}
@media (max-width: 560px) {
  [data-pugrid] { grid-template-columns: 1fr !important; }
  [data-sidetags] { display: none !important; }
}
`;

