// ============ ROADMAP (PRIVATE) ============
// EVENT_META: visual styling for each roadmap event kind
const EVENT_META = {
  rest:     { color: "#9aa3cc", icon: "moon",    tag: "REST DAY" },
  review:   { color: "#22d3ee", icon: "refresh", tag: "REVIEW" },
  project:  { color: "#22c55e", icon: "rocket",  tag: "NEW PROJECT" },
  flagship: { color: "#fbbf24", icon: "crown",   tag: "FLAGSHIP" },
  exam:     { color: "#f43f5e", icon: "cap",     tag: "AWS EXAM" },
  upgrade:  { color: "#a855f7", icon: "layers",  tag: "UPGRADE" },
};

function Roadmap({ progress, admin, openLogin }) {
  const { done, toggle, setLayerDone } = progress;
  const [active, setActive] = useState(1);

  if (!admin) {
    return (
      <div style={s.shell}>
        <div style={s.sec}>
          <div style={s.lockNote}>
            <span className="shine" />
            <div style={{ ...s.modalIcon, margin: "0 auto 18px" }}><Icon name="lock" size={26} color={C.gold} /></div>
            <h2 style={{ ...s.secTitle, fontSize: 26 }}>Roadmap is Private</h2>
            <p style={{ color: C.dim, fontSize: 15, marginTop: 12, fontWeight: 500 }}>
              The detailed learning roadmap is visible to Dharun only. Visitors can see overall progress on the Home page.
            </p>
            <button style={{ ...s.btnPrimary, marginTop: 22, justifyContent: "center" }} onClick={openLogin}>
              <Icon name="lock" size={15} /> Admin Login to View
            </button>
          </div>
        </div>
      </div>
    );
  }

  const layer = layers.find((l) => l.id === active);
  const layerSteps = steps.filter((x) => x.layer === active);
  const layerDone = layerSteps.filter((x) => done.has(x.num)).length;
  const lpct = layerSteps.length ? Math.round((layerDone / layerSteps.length) * 100) : 0;
  const layerEvents = (events || []).filter((e) => e.layer === active);
  // merge steps + events into a single day-keyed timeline
  const byDay = (() => {
    const m = {};
    layerSteps.forEach((x) => { (m[x.day] = m[x.day] || { steps: [], events: [] }).steps.push(x); });
    layerEvents.forEach((e) => { (m[e.day] = m[e.day] || { steps: [], events: [] }).events.push(e); });
    return Object.entries(m).sort((a, b) => Number(a[0]) - Number(b[0]));
  })();

  return (
    <div style={s.shell}>
      <div style={s.sec}>
        <div style={s.secHead}>
          <div style={s.secKicker}><Icon name="layers" size={14} color={C.cyan} /> THE ROADMAP ENGINE · PRIVATE</div>
          <h2 style={s.secTitle}>10 Layers · 365 Days · 610 Steps</h2>
          <p style={s.secSub}>Tap any step to mark it complete. The Home dashboard and Skills page update live.</p>
        </div>
        <div style={s.layerTabs}>
          {layers.map((l) => {
            const ls = steps.filter((x) => x.layer === l.id);
            const ld = ls.filter((x) => done.has(x.num)).length;
            const complete = ls.length > 0 && ld === ls.length;
            return (
              <button key={l.id} onClick={() => setActive(l.id)}
                style={{ ...s.layerTab, ...(active === l.id ? { borderColor: l.color, background: l.color + "26", color: "#fff" } : {}) }}>
                <span style={{ ...s.layerTabNum, background: l.color }}>{complete ? "✓" : l.id}</span>
                <span>{l.name}</span>
              </button>
            );
          })}
        </div>
        <div style={{ ...s.layerHead, ...glossyJS(layer.color) }}>
          <div style={s.layerHeadTop}>
            <div style={{ ...s.layerBadge, background: layer.color }}>LAYER {layer.id}</div>
            <div style={s.layerHeadMeta}>Steps {layer.steps} · Days {layer.days}</div>
          </div>
          <h3 style={s.layerHeadName}>{layer.name}</h3>
          <div style={s.layerHeadRows}>
            <div style={s.lhRow}><Icon name="cap" size={15} color={layer.color} /> {layer.course}</div>
            <div style={s.lhRow}><Icon name="code" size={15} color={layer.color} /> {layer.tools}</div>
            <div style={s.lhRow}><Icon name="rocket" size={15} color={layer.color} /> {layer.projects}</div>
          </div>
          <div style={s.layerHeadProg}>
            <div style={s.layerHeadTrack}><div style={{ ...s.layerHeadFill, width: `${lpct}%`, background: layer.color, boxShadow: `0 0 12px ${layer.color}` }} /></div>
            <div style={s.layerHeadPct}>{layerDone}/{layerSteps.length} · {lpct}%</div>
            <div style={s.adminBtns}>
              <button style={s.miniBtn} onClick={() => setLayerDone(active, true)}>Mark all</button>
              <button style={s.miniBtnGhost} onClick={() => setLayerDone(active, false)}>Reset</button>
            </div>
          </div>
        </div>
        <div style={s.dayList}>
          {byDay.map(([day, ds]) => (
            <div key={day}>
              <div style={s.dayHead}>
                <span style={{ ...s.dayPill, color: layer.color, borderColor: layer.color + "66" }}>
                  <Icon name="cal" size={13} color={layer.color} /> Day {day}
                </span>
                <div style={s.dayLine} />
              </div>
              {ds.events.map((ev, ei) => {
                const meta = EVENT_META[ev.kind] || EVENT_META.review;
                const evId = "evt-" + ev.day + "-" + ev.kind;
                const evDone = done.has(evId);
                return (
                  <button key={evId} onClick={() => toggle(evId)} style={{
                    display: "flex", alignItems: "center", gap: 12, width: "100%", textAlign: "left", font: "inherit", cursor: "pointer",
                    background: meta.color + (evDone ? "26" : "14"), border: "1px solid " + meta.color + (evDone ? "aa" : "55"),
                    borderRadius: 14, padding: "12px 16px", marginBottom: 8,
                  }}>
                    <div style={{
                      width: 26, height: 26, borderRadius: 8, flexShrink: 0, border: "2px solid " + meta.color + "99",
                      background: evDone ? meta.color : "transparent", display: "grid", placeItems: "center",
                    }}>
                      {evDone && <Icon name="check" size={14} color="#fff" />}
                    </div>
                    <div style={{
                      width: 30, height: 30, borderRadius: 9, flexShrink: 0,
                      background: meta.color + "26", display: "grid", placeItems: "center",
                    }}>
                      <Icon name={meta.icon} size={16} color={meta.color} />
                    </div>
                    <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
                      <span style={{ fontSize: 10.5, fontWeight: 800, letterSpacing: ".6px", color: meta.color }}>{meta.tag}</span>
                      <span style={{ fontSize: 14.5, fontWeight: 700, color: evDone ? C.dim : "#eaf0ff" }}>{ev.label}</span>
                    </div>
                  </button>
                );
              })}
              {ds.steps.map((st) => {
                const isDone = done.has(st.num);
                return (
                  <button key={st.num} onClick={() => toggle(st.num)}
                    style={{ ...s.stepCard, ...(isDone ? { borderColor: layer.color + "99", background: layer.color + "1a" } : {}) }}>
                    <div style={{ ...s.stepCheck, ...(isDone ? { background: layer.color, borderColor: layer.color } : {}) }}>
                      {isDone && <Icon name="check" size={14} color="#fff" />}
                    </div>
                    <div style={s.stepBody}>
                      <div style={s.stepTitleRow}>
                        <span style={{ ...s.stepNum, color: layer.color }}>STEP {st.num}</span>
                        <span style={{ ...s.stepTitle, ...(isDone ? { color: C.dim } : {}) }}>{st.title}</span>
                      </div>
                      {st.desc && <div style={s.stepDesc}>{st.desc}</div>}
                    </div>
                  </button>
                );
              })}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

