function ProjectDetail({ project, onClose, admin, links, setLinks, maxDay = 0 }) {
  const p = project;
  const cur = links[p.code] || {};
  const st = projectStatus(p, maxDay);
  const set = (k, v) => setLinks((prev) => ({ ...prev, [p.code]: { ...prev[p.code], [k]: v } }));
  const openUrl = (u) => { if (u) window.open(u, "_blank", "noopener,noreferrer"); };
  const tc = { Flagship: C.gold, Masterpiece: C.magenta, Ecosystem: C.blue };

  return (
    <div style={s.detailBg} onClick={onClose}>
      <div style={{ ...s.detail, ...glossyJS(p.accent) }} onClick={(e) => e.stopPropagation()}>
        <button style={s.detailClose} onClick={onClose}><Icon name="close" size={18} /></button>
        <div style={s.detailIcon}><Crest icon={p.icon} color={p.accent} size={72} iconSize={34} emoji={p.emoji} img={crownImg(p.code)} code={p.code} /></div>
        <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
          <span style={{ ...s.projCode, color: p.accent, borderColor: p.accent + "88" }}>{p.code}</span>
          <span style={{ ...s.projTag, background: tc[p.tag] + "33", color: "#fff", border: `1px solid ${tc[p.tag]}88` }}>{p.tag}</span>
          {st.built ? (
            <span style={{ display: "inline-flex", alignItems: "center", gap: 6, fontSize: 12.5, color: "#86efac", fontWeight: 800, background: "rgba(34,197,94,.15)", border: "1px solid rgba(34,197,94,.5)", borderRadius: 100, padding: "4px 12px" }}>
              <Icon name="check" size={12} color="#22c55e" /> Built · Day {p.day}
            </span>
          ) : (
            <span style={{ fontSize: 12.5, color: C.dim, fontWeight: 600 }}>Builds on Day {p.day}</span>
          )}
        </div>
        <div style={s.detailName}>{p.name}</div>
        <div style={s.detailLong}>{p.long}</div>
        {p.stack && p.stack.length > 0 && (
          <div style={s.detailStackRow}>{p.stack.map((t) => <span key={t} style={s.stackChip}>{t}</span>)}</div>
        )}

        {/* version timeline */}
        {p.versions && p.versions.length > 0 && (
          <div style={{ marginTop: 20 }}>
            <div style={{ ...s.secKicker, marginBottom: 6 }}><Icon name="git" size={13} color={p.accent} /> VERSION TIMELINE</div>
            {p.buildType && <div style={{ fontSize: 12.5, color: C.dim2, fontWeight: 600, marginBottom: 12 }}>{p.buildType}</div>}
            <div style={{ display: "flex", flexDirection: "column", gap: 9, position: "relative", paddingLeft: 6 }}>
              {p.versions.map((v, i) => {
                const vDone = st.lastIdx >= i;
                return (
                  <div key={i} style={{ display: "flex", alignItems: "center", gap: 11 }}>
                    {vDone ? (
                      <span style={{ width: 16, height: 16, borderRadius: 100, background: "#22c55e", boxShadow: "0 0 9px #22c55e", flexShrink: 0, display: "grid", placeItems: "center" }}>
                        <Icon name="check" size={10} color="#04140a" />
                      </span>
                    ) : (
                      <span style={{ width: 10, height: 10, borderRadius: 100, background: p.accent, boxShadow: `0 0 9px ${p.accent}`, flexShrink: 0, opacity: .4, margin: "0 3px" }} />
                    )}
                    <span style={{ fontSize: 13.5, color: vDone ? "#fff" : "#aab4dd", fontFamily: FM, fontWeight: vDone ? 700 : 500 }}>{v}</span>
                    {vDone && <span style={{ fontSize: 11.5, color: "#86efac", fontWeight: 800 }}>✓ Done</span>}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* link buttons (visible if link present) */}
        <div style={s.linkBtns}>
          {cur.live ? (
            <button style={{ ...s.linkBtn, ...glossyJS(C.green) }} onClick={() => openUrl(cur.live)}><Icon name="link" size={17} color="#fff" /> Open Live Project</button>
          ) : !admin ? <div style={s.comingSoon}><Icon name="link" size={15} /> Live link coming soon</div> : null}
          {cur.youtube ? (
            <button style={{ ...s.linkBtn, ...glossyJS("#ef4444") }} onClick={() => openUrl(cur.youtube)}><Icon name="play" size={16} color="#fff" /> Watch Demo Video</button>
          ) : !admin ? <div style={s.comingSoon}><Icon name="play" size={15} /> Demo video coming soon</div> : null}
          {cur.github ? (
            <button style={{ ...s.linkBtn, ...glossyJS("#6366f1") }} onClick={() => openUrl(cur.github)}><Icon name="github" size={17} color="#fff" /> View Code on GitHub</button>
          ) : !admin ? <div style={s.comingSoon}><Icon name="github" size={15} /> GitHub repo coming soon</div> : null}
        </div>

        {/* admin paste inputs */}
        {admin && (
          <div style={{ marginTop: 18, borderTop: "1px solid " + C.border, paddingTop: 16 }}>
            <div style={{ ...s.secKicker, marginBottom: 12 }}><Icon name="pencil" size={13} color={C.green} /> ADMIN — PASTE LINKS</div>
            <div style={s.linkInputRow}>
              <span style={s.linkLabel}><Icon name="link" size={13} color={C.green} /> Live Project Link</span>
              <input style={s.linkInput} placeholder="https://..." value={cur.live || ""} onChange={(e) => set("live", e.target.value)} />
            </div>
            <div style={s.linkInputRow}>
              <span style={s.linkLabel}><Icon name="play" size={13} color="#ef4444" /> YouTube Demo Link</span>
              <input style={s.linkInput} placeholder="https://youtube.com/..." value={cur.youtube || ""} onChange={(e) => set("youtube", e.target.value)} />
            </div>
            <div style={s.linkInputRow}>
              <span style={s.linkLabel}><Icon name="github" size={13} color="#a5b4fc" /> GitHub Repo Link</span>
              <input style={s.linkInput} placeholder="https://github.com/..." value={cur.github || ""} onChange={(e) => set("github", e.target.value)} />
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

