// password input with show/hide eye
function PwInput({ value, onChange, placeholder, autoFocus, onEnter, error }) {
  const [show, setShow] = useState(false);
  return (
    <div style={{ position: "relative", marginBottom: 14 }}>
      <input type={show ? "text" : "password"} value={value} autoFocus={autoFocus}
        onChange={onChange} onKeyDown={(e) => e.key === "Enter" && onEnter && onEnter()}
        placeholder={placeholder} style={{ ...s.input, marginBottom: 0, paddingRight: 46, ...(error ? { borderColor: "#f43f5e" } : {}) }} />
      <button type="button" onClick={() => setShow(!show)} title={show ? "Hide" : "Show"}
        style={{ position: "absolute", right: 8, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", color: C.dim, cursor: "pointer", padding: 6, display: "grid", placeItems: "center" }}>
        <Icon name={show ? "eyeoff" : "eye"} size={18} />
      </button>
    </div>
  );
}

// ============ LOGIN MODAL ============
function LoginModal({ onClose, onSuccess, password, adminEmail }) {
  const [mode, setMode] = useState("password"); // password | email | forgot
  const [pw, setPw] = useState(""); const [err, setErr] = useState(false);
  const [email, setEmail] = useState(""); const [emailErr, setEmailErr] = useState("");
  const [forgotMsg, setForgotMsg] = useState("");

  const submitPw = () => { if (pw === password) { onSuccess(); onClose(); } else { setErr(true); setPw(""); } };
  const submitEmail = () => {
    if (email.trim().toLowerCase() === adminEmail.toLowerCase()) { onSuccess(); onClose(); }
    else { setEmailErr("This email is not registered as admin."); }
  };
  const submitForgot = () => {
    if (email.trim().toLowerCase() === adminEmail.toLowerCase()) {
      setForgotMsg("✓ A password reset link would be sent to your email. (Works after the site is hosted online.)");
    } else { setForgotMsg("This email is not registered as admin."); }
  };

  return (
    <div style={s.modalBg} onClick={onClose}>
      <div style={s.modal} onClick={(e) => e.stopPropagation()}>
        <button style={s.modalClose} onClick={onClose}><Icon name="close" size={18} /></button>
        <div style={s.modalIcon}><span className="shine" /><Icon name="lock" size={26} color="#fff" /></div>

        {mode === "password" && <>
          <div style={s.modalTitle}>Admin Access</div>
          <div style={s.modalSub}>Enter your password to unlock the roadmap &amp; edit mode.</div>
          <PwInput value={pw} autoFocus onChange={(e) => { setPw(e.target.value); setErr(false); }} onEnter={submitPw} placeholder="Password" error={err} />
          {err && <div style={s.errText}>Incorrect password. Try again.</div>}
          <button style={{ ...s.btnPrimary, width: "100%", justifyContent: "center" }} onClick={submitPw}>Unlock <Icon name="arrow" size={16} /></button>
          <div style={s.loginAlt}>
            <button style={s.loginAltBtn} onClick={() => { setMode("email"); setErr(false); }}><Icon name="mail" size={13} /> Login with Email</button>
            <button style={s.loginAltBtn} onClick={() => { setMode("forgot"); setForgotMsg(""); }}>Forgot Password?</button>
          </div>
        </>}

        {mode === "email" && <>
          <div style={s.modalTitle}>Login with Email</div>
          <div style={s.modalSub}>Enter your registered admin email address.</div>
          <input type="email" value={email} autoFocus onChange={(e) => { setEmail(e.target.value); setEmailErr(""); }}
            onKeyDown={(e) => e.key === "Enter" && submitEmail()} placeholder="you@email.com" style={{ ...s.input, ...(emailErr ? { borderColor: "#f43f5e" } : {}) }} />
          {emailErr && <div style={s.errText}>{emailErr}</div>}
          <button style={{ ...s.btnPrimary, width: "100%", justifyContent: "center" }} onClick={submitEmail}>Login <Icon name="arrow" size={16} /></button>
          <div style={s.loginAlt}>
            <button style={s.loginAltBtn} onClick={() => { setMode("password"); setEmailErr(""); }}><Icon name="lock" size={13} /> Use Password</button>
          </div>
        </>}

        {mode === "forgot" && <>
          <div style={s.modalTitle}>Reset Password</div>
          <div style={s.modalSub}>Enter your admin email to receive a reset link.</div>
          <input type="email" value={email} autoFocus onChange={(e) => { setEmail(e.target.value); setForgotMsg(""); }}
            onKeyDown={(e) => e.key === "Enter" && submitForgot()} placeholder="you@email.com" style={s.input} />
          {forgotMsg && <div style={forgotMsg[0] === "✓" ? s.okText : s.errText}>{forgotMsg}</div>}
          <button style={{ ...s.btnPrimary, width: "100%", justifyContent: "center" }} onClick={submitForgot}>Send Reset Link <Icon name="mail" size={15} /></button>
          <div style={s.loginAlt}>
            <button style={s.loginAltBtn} onClick={() => { setMode("password"); setForgotMsg(""); }}><Icon name="lock" size={13} /> Back to Login</button>
          </div>
        </>}
      </div>
    </div>
  );
}

// ============ CHANGE PW MODAL ============
function ChangePwModal({ onClose, current, onChange }) {
  const [cur, setCur] = useState(""); const [nw, setNw] = useState(""); const [cf, setCf] = useState("");
  const [err, setErr] = useState(""); const [ok, setOk] = useState(false);
  const submit = () => {
    if (cur !== current) { setErr("Current password is incorrect."); return; }
    if (nw.length < 4) { setErr("New password must be at least 4 characters."); return; }
    if (nw !== cf) { setErr("New passwords do not match."); return; }
    onChange(nw); setOk(true); setErr(""); setTimeout(onClose, 1100);
  };
  return (
    <div style={s.modalBg} onClick={onClose}>
      <div style={s.modal} onClick={(e) => e.stopPropagation()}>
        <button style={s.modalClose} onClick={onClose}><Icon name="close" size={18} /></button>
        <div style={s.modalIcon}><span className="shine" /><Icon name="settings" size={26} color="#fff" /></div>
        <div style={s.modalTitle}>Change Password</div>
        <div style={s.modalSub}>Update your admin password.</div>
        <div style={s.inputLabel}>Old Password</div>
        <PwInput value={cur} onChange={(e) => { setCur(e.target.value); setErr(""); }} placeholder="Old password" />
        <div style={s.inputLabel}>New Password</div>
        <PwInput value={nw} onChange={(e) => { setNw(e.target.value); setErr(""); }} placeholder="New password" />
        <div style={s.inputLabel}>Confirm Password</div>
        <PwInput value={cf} onChange={(e) => { setCf(e.target.value); setErr(""); }} onEnter={submit} placeholder="Confirm new password" />
        {err && <div style={s.errText}>{err}</div>}
        {ok && <div style={s.okText}>✓ Password updated successfully!</div>}
        <button style={{ ...s.btnPrimary, width: "100%", justifyContent: "center" }} onClick={submit}>Save New Password</button>
      </div>
    </div>
  );
}

