// ===== build/upgrade status helpers (driven by roadmap maxDay) =====
function versionDay(v) {
  const m = /Day\s+(\d+)/.exec(v || "");
  return m ? parseInt(m[1], 10) : null;
}
function projectStatus(p, maxDay) {
  const vers = p.versions || [];
  let lastIdx = -1;
  vers.forEach((v, i) => { const d = versionDay(v); if (d != null && maxDay >= d) lastIdx = i; });
  const built = lastIdx >= 0;
  const currentLabel = built ? vers[lastIdx] : (vers[0] || ("Builds on Day " + p.day));
  return { built, lastIdx, currentLabel, total: vers.length };
}

