// ============ PROGRESS HOOK ============
// persistent certificate links (subcourse certs + AWS certs), saved to browser storage
const CERT_STORE_KEY = "dharun-cert-links-v1";
function useCertLinks() {
  const [certLinks, setCertLinks] = useState({});
  const [loaded, setLoaded] = useState(false);
  // load once on mount
  useEffect(() => {
    let alive = true;
    (async () => {
      try {
        const res = await sbGet(CERT_STORE_KEY);
        if (alive && res && res.value) setCertLinks(JSON.parse(res.value));
      } catch (e) { /* no saved data yet */ }
      if (alive) setLoaded(true);
    })();
    return () => { alive = false; };
  }, []);
  // persist on every change (after initial load)
  useEffect(() => {
    if (!loaded) return;
    (async () => {
      try {
        await sbSet(CERT_STORE_KEY, JSON.stringify(certLinks));
      } catch (e) { /* ignore write errors */ }
    })();
  }, [certLinks, loaded]);
  const setCertLink = (key, url) =>
    setCertLinks((prev) => {
      const next = { ...prev };
      if (url && url.trim()) next[key] = url.trim();
      else delete next[key];
      return next;
    });
  return { certLinks, setCertLink };
}

function useProgress() {
  const [done, setDone] = useState(() => new Set());
  useEffect(() => {
  sbGet("dharun-progress-done").then(r => {
    if (r && r.value) setDone(new Set(JSON.parse(r.value)));
  });
}, []);
useEffect(() => {
  sbSet("dharun-progress-done", JSON.stringify([...done]));
}, [done]);
  const toggle = (n) => setDone((p) => { const x = new Set(p); x.has(n) ? x.delete(n) : x.add(n); return x; });
  const setLayerDone = (lid, val) => setDone((p) => {
    const x = new Set(p);
    // toggle every numbered step in this layer
    steps.filter((st) => st.layer === lid).forEach((st) => val ? x.add(st.num) : x.delete(st.num));
    // also toggle every roadmap event in this layer (rest / project / flagship / upgrade / exam / review)
    (events || []).filter((e) => e.layer === lid).forEach((e) => {
      const id = "evt-" + e.day + "-" + e.kind;
      val ? x.add(id) : x.delete(id);
    });
    return x;
  });
  return { done, toggle, setLayerDone };
}

// ============ APP ============
export default function App() {
  const [page, setPage] = useState("home");
  const [admin, setAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [showPw, setShowPw] = useState(false);
  const [showGuide, setShowGuide] = useState(false);
  const [password, setPassword] = useState("dharun2026"); useEffect(() => { sbGet("dharun-admin-password").then(r => { if (r && r.value) setPassword(r.value); }); }, []);
  const [adminEmail] = useState("dharun.vishnu@gmail.com");
  const [activeProject, setActiveProject] = useState(null);
  const [links, setLinks] = useState({});
  const [repos, setRepos] = useState([]);
  const progress = useProgress();
  const done = progress.done;
  const { certLinks, setCertLink } = useCertLinks();

  const stats = useMemo(() => {
    const doneSteps = steps.filter((x) => done.has(x.num));
    const stepCount = doneSteps.length;
    // also count ticked roadmap events (rest/project/flagship/upgrade/exam/review)
    // toward both the day count AND maxDay, so rest days and project days are
    // included in "Days" and ticking a build day flips its status that same day
    const doneEventDays = (events || [])
      .filter((e) => done.has("evt-" + e.day + "-" + e.kind))
      .map((e) => e.day);
    // unique calendar days completed = step-days + event-days combined
    const dayset = new Set(doneSteps.map((x) => x.day).concat(doneEventDays));
    const allDoneDays = doneSteps.map((x) => x.day).concat(doneEventDays);
    const maxDay = allDoneDays.length ? Math.max(...allDoneDays) : 0;
    const projectsDone = projects.filter((p) => p.day <= maxDay && maxDay > 0).length;
    // Certificates: total = all subcourse certs (across 8 courses) + 3 AWS certs.
    // earned = number of certificate links actually pasted (persisted in certLinks).
    const totalSubCerts = (courses || []).reduce((sum, c) => sum + ((c.subs && c.subs.length) || 0), 0);
    const totalCerts = totalSubCerts + (certs ? certs.length : 0);
    const certsDone = Object.keys(certLinks || {}).length;
    return { steps: stepCount, days: dayset.size, projects: projectsDone, certs: certsDone, totalCerts, commits: stepCount * 3, pct: Math.round((stepCount / 610) * 100), maxDay };
  }, [done, certLinks]);

  const go = (id) => { setPage(id); window.scrollTo({ top: 0, behavior: "smooth" }); };
  const openProject = (p) => setActiveProject(p);

  return (
    <div style={s.app}>
      <style>{css}</style>
      <div style={s.bgFx} />
      <div style={s.grid} />
      <Nav page={page} go={go} admin={admin} openLogin={() => setShowLogin(true)} logout={() => { setAdmin(false); if (page === "roadmap") go("home"); }} />

      {admin && (
        <div style={s.shell}>
          <div style={s.adminBar}>
            <span className="shine" />
            <div style={s.adminBarLeft}><Icon name="pencil" size={15} /> Admin mode active — roadmap unlocked, links &amp; settings editable</div>
            <div style={s.adminBarBtns}>
              <button style={s.miniBtn} onClick={() => go("roadmap")}><Icon name="layers" size={12} /> Open Roadmap</button>
              <button style={s.miniBtn} onClick={() => setShowGuide(true)}><Icon name="cap" size={12} /> Learn &amp; Edit</button>
              <button style={s.miniBtn} onClick={() => setShowPw(true)}><Icon name="settings" size={12} /> Change Password</button>
              <button style={s.miniBtnGhost} onClick={() => { setAdmin(false); if (page === "roadmap") go("home"); }}>Exit</button>
            </div>
          </div>
        </div>
      )}

      <main>
        {page === "home" && <Home go={go} stats={stats} openProject={openProject} admin={admin} repos={repos} setRepos={setRepos} />}
        {page === "journey" && <Journey progress={progress} />}
        {page === "roadmap" && <Roadmap progress={progress} admin={admin} openLogin={() => setShowLogin(true)} />}
        {page === "projects" && <Projects openProject={openProject} />}
        {page === "myprojects" && <MyProjects openProject={openProject} links={links} stats={stats} />}
        {page === "commits" && <Commits stats={stats} />}
        {page === "versions" && <Versions openProject={openProject} />}
        {page === "certs" && <Certs admin={admin} certLinks={certLinks} setCertLink={setCertLink} stats={stats} />}
        {page === "contact" && <Contact />}
        {page === "techstack" && <TechStack stats={stats} />}
      </main>

      <Footer />
      {activeProject && <ProjectDetail project={activeProject} onClose={() => setActiveProject(null)} admin={admin} links={links} setLinks={setLinks} maxDay={stats.maxDay} />}
      {showLogin && <LoginModal onClose={() => setShowLogin(false)} onSuccess={() => { setAdmin(true); go("roadmap"); }} password={password} adminEmail={adminEmail} />}
      {showPw && <ChangePwModal onClose={() => setShowPw(false)} current={password} onChange={async (newPw) => { setPassword(newPw); await sbSet("dharun-admin-password", newPw); }} />}
      {showGuide && <GuideModal onClose={() => setShowGuide(false)} />}
    </div>
  );
}
